SELECT metric_name
FROM requirement_metrics
WHERE is_key_metric = 1;

SELECT version_text
FROM requirement_versions
WHERE is_current_version = 1 AND version_status = 'approved';

SELECT type_name
FROM requirement_types
WHERE is_customizable = 0;

SELECT COUNT(*) AS unresolved_comments_count
FROM requirement_comments
WHERE is_resolved = 0;
